VALUES
  ('social-worker-moex-02891', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '新管理主義1970年代之後，成為英國政府進行福利改革的重要理念依據，請問下列描述何者較符合此一 精神？', '["強調經濟（economy）、效率（efficiency）及效標（criteria）", "結合民間團體力量，擴大補助範圍", "增加社會福利預算活絡福利市場", "透過準市場與購買服務的方式，促進類似市場的競爭機制，提升效能"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02892', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會工作管理在近二十年的發展，逐漸借用企業管理的理念與方法，然而在本質上仍有不同之處。下列 對於社會工作管理異於企業管理的特質之敘述，何者是較貼切的？', '["社會工作管理以「案量」為基礎", "社會工作管理講求「愛心」或「付出」", "社會工作之「服務」或「治療」成效容易混淆", "社會服務管理的服務績效評估是為向政府有所交代"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02893', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會工作管理者遭遇倫理困境，往往導因於其所持的價值與職務產生衝突。若社工發生上述之倫理困境 時，以案主系統與其利害關係人之長期福祉為最大考量，誠實、負責且公開的表現，建立彼此協議之公 平協議。此一方式較符合下列何種型態？', '["對自己，也對社會負責", "對專業發展與才能負責", "對專業負責", "對個案和重要他人負責"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02894', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '管理者基於保護性社會工作的實務內容繁雜，所以思考保護性工作的每一名社工督導所督導的社會工作 員人數不宜太多。那麼這位管理者是從那一個角度在思考組織管理的工作？', '["集權化", "指揮鏈", "控制幅度", "組織願景"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02895', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在社會工作管理中能夠善用充權觀點（empowering approach）的領導者是屬於那一種類型的領導？', '["轉換型領導（transformational leadership）", "威權式領導（authoritarian leadership）", "指導型領導（directive leadership）", "交易型領導（transactional leadership）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02896', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '所有的非營利組織（特別是社會服務部門）大多希望能有更多的經費，這並非是一種貪念，而是組織需 要充足之經費來達成目標，並提供個案高品質的服務。因此下列何項經費來源是影響社會服務組織發展 的首要因素？', '["政府補助或契約", "募款", "民間部門撥補", "收費"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02897', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '委外責信的邏輯本質上是明列契約雙方相互的期待、責任與義務，公部門的行動者根據契約中明列的服 務項目與執行成效進行監督，並檢視契約所要購買的產品或服務是否依約完成。依據Romzek and Dubnick （1987）提出完整的責信理論，倘若委外單位因處理個案費時，造成平均單位服務費用提高，且服務案 量遠低於契約內之規定，則該委外單位最主要的責信問題為何？', '["層級責信（hierarchical accountability）", "專業責信（professional accountability）", "法律責信（legal accountability）", "政治責信（political accountability）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02898', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會福利組織透過管理資訊系統（management information system, MIS）能夠提供行銷管理者及直接服務 管理者重要的訊息。請問下列那一種MIS的次系統能夠協助建立指標、並尋找組織邁向目標過程中可能 遭遇到的問題？', '["人力資源資訊系統（human resource information system, HRIS）", "績效導向系統（performance-directed system, PDS）", "行銷募款系統（marketing and fund-raising system, MFRS）", "資訊報告系統（information reporting system）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02899', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某一個社福團體邀請知名藝人代言廣告，由於代言者形象清新，能夠讓社會大眾清楚了解社福團體的主 要特質、信譽及執行能力。以上描述社福團體所從事的活動比較符合下列何者？', '["公共關係（public relations）", "行銷（marketing）", "市場區隔（market segmentation）", "市場定位（market positioning）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02900', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', 'Doherty and Horne（2002）在傳統的市場定位與行銷組合「4P」的基礎上建構出公共服務行銷的「5P」模 式，請問以下何者對「5P」模式的內容描述正確？', '["Package (product), Promotion, Place, Price, People", "Proposal, Promotion, Place, Price, People", "Proposal, Promotion, Peace, Price, People", "Package (product), Promotion, Peace, Price, People"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
